			],
			activeBurrowIds: new Set(),
			latestEndedAt: new Map(),
			ttlMs: 60 * 60_000,
			now: NOW,
		});
		expect(out.map((s) => s.burrowId)).toEqual(["bur_b", "bur_a"]);
	});

	test("skips rows with an unparseable timestamp", () => {
		const out = findStrandedBurrows({
			burrows: [burrow("bur_bad", "not-a-date")],
			activeBurrowIds: new Set(),
			latestEndedAt: new Map(),
			ttlMs: 60 * 60_000,
			now: NOW,
